import{_ as e,o as n,c as i,a}from"./app.b75dfbe6.js";var t="/aktivitaeten/a47rs/A47RS.jpg",r="/aktivitaeten/a47rs/yousuf.jpg",s="/aktivitaeten/a47rs/1784823632429.jpg",h="/aktivitaeten/a47rs/1784823632437.jpg",c="/aktivitaeten/a47rs/1784823632420.jpg",d="/aktivitaeten/a47rs/1784823632416.jpg";const o={},u=a('<h1 id="koniglich-on-the-air" tabindex="-1"><a class="header-anchor" href="#koniglich-on-the-air" aria-hidden="true">#</a> K\xF6niglich On The Air</h1><h2 id="zu-gast-bei-der-hq-station-der-royal-omani-amateur-radio-society" tabindex="-1"><a class="header-anchor" href="#zu-gast-bei-der-hq-station-der-royal-omani-amateur-radio-society" aria-hidden="true">#</a> Zu Gast bei der HQ Station der Royal Omani Amateur Radio Society</h2><p>Ich bin zur Zeit \xF6fter dienstlich in Maskat in Oman unterwegs. Das ist nat\xFCrlich kein CEPT-Land und eine Gastlizenz bekommt man auch nicht so einfach. Eigenes Equipment mitbringen und benutzen geht schon gar nicht. So sa\xDF ich also bisher abends meistens im Hotel und dachte, schade dass ich nicht meinem sch\xF6nsten Hobby der Welt nachgehen kann.</p><p>Schon vor meiner ersten Reise hatte ich gesehen, dass es auch hier einen Amateurfunkverband gibt und dessen Clubstation gar nicht so weit weg ist. Also hatte ich dort per Mail angefragt, ob es m\xF6glich ist mal zu Besuch vorbei zu kommen. Leider lange gar keine Antwort. Dann kam aber doch die Best\xE4tigung, ja man k\xF6nnte das HQ besuchen, t\xE4glich au\xDFer am Wochenende (hier Freitag und Samstag) von 17 bis 20 Uhr. Also hab ich mich heute nach der Arbeit ins Taxi gesetzt und bin einfach mal vorbei gefahren.</p><p>Das HQ liegt ein wenig am Rand der Stadt, nicht weit vom Strand. Schon von au\xDFen sehen Eingeweihte wie wir was hier gespielt wird, beeindruckende Beams gr\xFC\xDFen vom Dach.</p><p><img src="'+t+'" alt=""></p><p>Die T\xFCr war offen, vorsichtig schlich ich mich hinein und traf gleich auf 2 OMs, die mich direkt nach meinem Callsign fragten und herzlich begr\xFC\xDFten. Nachdem ich mich im G\xE4stebuch eingetragen hatte wurde mir die Station gezeigt. Yousuf A41UX stellte sich als begeisterter Sat-OP vor und zeigte mir gleich die von ihm entwickelte App, die den Sat-Betrieb sehr vereinfachen kann. Hier kann man sie runterladen und ausprobieren: https://www.unixeer.com/ham_satting/index.html Das ist nur eine von zahlreichen Afu-Apps die man auf seiner Website finden kann.</p><p><img src="'+r+'" alt=""></p><p>Dann kamen noch andere OMs und begr\xFC\xDFten mich freundlich und boten mir gleich an, Betrieb von der HQ Station zu machen. Irgendwelche Formalit\xE4ten waren dazu gar nicht n\xF6tig.<br> Das lie\xDF ich mir nicht zweimal sagen und nachdem die Technik lief rief ich mit dem Clubcall auf 20m &quot;CQ A74RS&quot;. Zum ersten Mal im Leben war ich mit gut 1,2 kW on Air.</p><p>Leider waren die Bedingungen doch recht bescheiden, nach Aussage der lokalen OMs lag das u.A. an den aktuellen Ereignissen die ja gerade nicht weit von uns hier stattfinden. Jede Menge Radar und andere HF in der Luft f\xFChrte dazu, dass ich die anrufenden Stationen oft nur schwer aus dem Rauschen fischen konnte. Zum Gl\xFCck gelangen doch QSOs mit 2 Drau\xDFenfunkern, danke an DL9CE und DM6SB f\xFCr die Geduld. Aus Europa kamen sonst vor allem polnische und \xD6stereichische Stationen an.</p><p>Sp\xE4ter probierte ich noch etwas 17m was ein wenig besser lief. 15m war leider ganz tot.</p><p><img src="'+s+'" alt=""><img src="'+h+'" alt=""><img src="'+c+'" alt=""></p><p>Nach gut einer Stunde hab ich dann QRT gemacht. Ich hoffe das demn\xE4chst noch einmal wiederholen zu k\xF6nnen, vielleicht sind die Bedingungen dann besser und ich erreiche auch mehr Drau\xDFenfunker.</p><p>Das war ein sehr sch\xF6ner Abend, mni tnx an die omanischen Hams f\xFCr ihre gro\xDFartige Gastfreundschaft und 73 von Haiko, A47RS / DF9HC</p><p><img src="'+d+'" alt=""></p>',15),m=[u];function g(l,p){return n(),i("div",null,m)}var b=e(o,[["render",g],["__file","2026-07-23-A47RS.html.vue"]]);export{b as default};
